    assert_eq!(bear_before, 2);

    g.perform_action(GameAction::CastSpell {
        card_id: lash,
        target: Some(Target::Permanent(bear)),
        additional_targets: vec![],
        mode: None, x_value: None,
    })
    .expect("Lash of Malice castable for {B}");
