    // After casting, hand = 4 islands. 2*4 = 8 +1/+1 counters.
    let fractal = g.battlefield.iter()
        .find(|c| c.controller == 0 && c.is_token && c.definition.name == "Fractal")
        .expect("Fractal minted");
