    // ETB minted a Fractal with one +1/+1 counter.
    let fractals: Vec<_> = g
        .battlefield
        .iter()
        .filter(|c| c.definition.subtypes.creature_types.contains(&CreatureType::Fractal))
        .map(|c| c.id)
        .collect();
    assert!(!fractals.is_empty());
    // Cast an instant - calcographer grows.
