    // Magecraft check: cast a bolt and verify scry didn't crash / library
    // size stayed >= 0.
    let lib_before = g.players[0].library.len();
    let bolt = g.add_card_to_hand(0, catalog::lightning_bolt());
    g.players[0].mana_pool.add(Color::Red, 1);
